Percentage = document.getElementById('ei-percentage');    elements.snPercentage = document.getElementById('sn-percentage');    elements.tfPercentage = document.getElementById('tf-percentage');    elements.jpPercentage = document.getElementById('jp-percentage');    elements.totalEnergyUsed = document.getElementById('total-energy-used');    elements.totalLogicUsed = document.getElementById('total-logic-used');    elements.totalEmpathyUsed = document.getElementById('total-empathy-used');    elements.energyPercentage = document.getElementById('energy-percentage');    elements.logicPercentage = document.getElementById('logic-percentage');    elements.empathyPercentage = document.getElementById('empathy-percentage');    elements.resourceEnergyBar = document.getElementById('resource-energy-bar');    elements.resourceLogicBar = document.getElementById('resource-logic-bar');    elements.resourceEmpathyBar = document.getElementById('resource-empathy-bar');    elements.unlockedCount = document.getElementById('unlocked-count');    elements.unlockedBar = document.getElementById('unlocked-bar');    elements.adviceContent = document.getElementById('advice-content');    elements.notificationAnalysis = document.getElementById('notification-analysis');        // зІ’еӯҗе®№еҷЁ    elements.particlesContainer = document.getElementById('particles-container');        // з»‘е®ҡдәӢд»¶    bindEvents();        // жҙ—зүҢеҚЎзүҢ    gameState.cards = shuffleArray([...expandedCards]);}// жҙ—зүҢеҮҪж•°function shuffleArray(array) {    for (let i = array.length - 1; i > 0; i--) {        const j = Math.floor(Math.random() * (i + 1));        [array[i], array[j]] = [array[j], array[i]];    }    return array;}// з»‘е®ҡдәӢд»¶function bindEvents() {    // ејҖе§ӢжёёжҲ?    elements.startBtn.addEventListener('click', startGame);        // иҝ”еӣһйҰ–йЎө    elements.backHomeBtn.addEventListener('click', () => {        window.location.href = 'index.html';    });    elements.homeBtnMain.addEventListener('click', () => {        window.location.href = 'index.html';    });    elements.homeBtnResult.addEventListener('click', () => {        window.location.href = 'index.html';    });        // йҮҚж–°ејҖе§?    elements.restartBtn.addEventListener('click', resetGame);        // еӨҚеҲ¶з»“жһң    elements.copyResultBtn.addEventListener('click', copyResult);        // з”ҹжҲҗеҲҶдә«еҚЎзүҮ    elements.shareCardBtn.addEventListener('click', generateShareCard);        // е…ій—ӯйҖҡзҹҘ    elements.closeNotificationBtn.addEventListener('click', hideNotification);    elements.dismissNotificationBtn.addEventListener('click', () => {        if (gameState.selectedNotificationOption !== null) {            handleNotificationChoice(gameState.selectedNotificationOption);        }    });        // иҜҙжҳҺеј№зӘ—    elements.showGuideBtn.addEventListener('click', () => {        elements.guidePopup.classList.remove('hidden');        gameState.guideShown = true;    });    elements.closeGuideBtn.addEventListener('click', () => {        elements.guidePopup.classList.add('hidden');    });        // жӢ–жӢҪдәӢд»¶    initDragDrop();}// еҲқе§ӢеҢ–жӢ–жӢҪеҠҹиғ?function initDragDrop() {    const card = elements.card;    let longPressTimer = null;        // йј ж Ү/и§Ұж‘ёдәӢд»¶    const startEvent = (e) => {        if (gameState.currentPage !== 'game') return;                const touch = e.touches ? e.touches[0] : e;        gameState.dragData.isDragging = true;        gameState.dragData.isLongPressing = false;        gameState.dragData.startX = touch.clientX;        gameState.dragData.startY = touch.clientY;        gameState.dragData.startTime = Date.now();        gameState.dragData.trail = [];                // й•ҝжҢүжЈҖжө?- 500msеҗҺи§ҰеҸ‘йҖүйЎ№ж”ҫеӨ§        longPressTimer = setTimeout(() => {            if (gameState.dragData.isDragging) {                gameState.dragData.isLongPressing = true;                // йҖүйЎ№ж”ҫеӨ§еҸ‘е…ү                elements.slotA.classList.add('highlight');                elements.slotB.classList.add('highlight');                elements.slotC.classList.add('highlight');                elements.slotD.classList.add('highlight');            }        }, 500);                card.classList.add('dragging');        document.body.style.cursor = 'grabbing';                // и®°еҪ•еҲқе§ӢдҪҚзҪ®        const rect = card.getBoundingClientRect();        gameState.dragData.originalX = rect.left;        gameState.dragData.originalY = rect.top;    };        const moveEvent = (e) => {        if (!gameState.dragData.isDragging) return;                e.preventDefault();        const touch = e.touches ? e.touches[0] : e;                const deltaX = touch.clientX - gameState.dragData.startX;        const deltaY = touch.clientY - gameState.dragData.startY;                // жЈҖжөӢжҳҜеҗҰеңЁйҖүйЎ№еҢәеҹҹдёҠж–№        const isOverSlot = checkHoverTargets(touch.clientX, touch.clientY);                // з§»еҠЁеҚЎзүҢ - еҰӮжһңеңЁйҖүйЎ№дёҠж–№еҲҷзј©е°ҸеҲ°йҖүйЎ№еӨ§е°Ҹ        let scale = 1.05;        if (isOverSlot && gameState.dragData.isLongPressing) {            // йҖүйЎ№еӨ§е°Ҹжҳ?60pxГ—128pxпјҢи®Ўз®—зј©ж”ҫжҜ”дҫ?            const cardRect = card.getBoundingClientRect();            const targetWidth = 160;            const targetHeight = 128;            scale = Math.min(targetWidth / cardRect.width, targetHeight / cardRect.height);        }                card.style.transform = `translate(${deltaX}px, ${deltaY}px) scale(${scale})`;                // и®°еҪ•иҪЁиҝ№        gameState.dragData.trail.push({            x: touch.clientX,            y: touch.clientY,            time: Date.now()        });                // еҲӣе»әжӢ–е°ҫж•Ҳжһң        createDragTrail(touch.clientX, touch.clientY);    };        const endEvent = (e) => {        // жё…йҷӨй•ҝжҢүи®Ўж—¶еҷ?        if (longPressTimer) {            clearTimeout(longPressTimer);            longPressTimer = null;        }                if (!gameState.dragData.isDragging) return;                const touch = e.changedTouches ? e.changedTouches[0] : e;                // жё…йҷӨй•ҝжҢүж•Ҳжһң        gameState.dragData.isLongPressing = false;        elements.slotA.classList.remove('highlight', 'recommended');        elements.slotB.classList.remove('highlight', 'recommended');        elements.slotC.classList.remove('highlight', 'recommended');        elements.slotD.classList.remove('highlight', 'recommended');                // жЈҖжҹҘжҳҜеҗҰжӢ–еҲ°дәҶжңүж•ҲдҪҚзҪ®        const result = checkDropTarget(touch.clientX, touch.clientY);                if (result) {            handleDrop(result);        } else {            // еј№еӣһеҺҹдҪҚ            card.style.transform = '';            card.classList.remove('dragging');            createFailureParticles(touch.clientX, touch.clientY);        }                gameState.dragData.isDragging = false;        document.body.style.cursor = '';                // жё…зҗҶй«ҳдә®        elements.logicEye.classList.remove('highlight');        elements.empathyEye.classList.remove('highlight');    };        // з»‘е®ҡйј ж ҮдәӢд»¶    card.addEventListener('mousedown', startEvent);    document.addEventListener('mousemove', moveEvent);    document.addEventListener('mouseup', endEvent);        // з»‘е®ҡи§Ұж‘ёдәӢд»¶    card.addEventListener('touchstart', startEvent, { passive: false });    document.addEventListener('touchmove', moveEvent, { passive: false });    document.addEventListener('touchend', endEvent);}// жЈҖжҹҘжӮ¬еҒңзӣ®ж ?function checkHoverTargets(x, y) {    const slotA = elements.slotA.getBoundingClientRect();    const slotB = elements.slotB.getBoundingClientRect();    const slotC = elements.slotC.getBoundingClientRect();    const slotD = elements.slotD.getBoundingClientRect();    const logicEye = elements.logicEye.getBoundingClientRect();    const empathyEye = elements.empathyEye.getBoundingClientRect();        const isOverSlotA = isOverElement(x, y, slotA);    const isOverSlotB = isOverElement(x, y, slotB);    const isOverSlotC = isOverElement(x, y, slotC);    const isOverSlotD = isOverElement(x, y, slotD);    const isOverLogicEye = isOverElement(x, y, logicEye);    const isOverEmpathyEye = isOverElement(x, y, empathyEye);        // жё…йҷӨжүҖжңүй«ҳдә®пјҲйҷӨдәҶй•ҝжҢүж”ҫеӨ§ж•Ҳжһңпј?    if (!gameState.dragData.isLongPressing) {        elements.slotA.classList.remove('highlight');        elements.slotB.classList.remove('highlight');        elements.slotC.classList.remove('highlight');        elements.slotD.classList.remove('highlight');    }    elements.logicEye.classList.remove('highlight');    elements.empathyEye.classList.remove('highlight');        // жё…йҷӨжүҖжңүhoveringзұ?    elements.slotA.classList.remove('hovering');    elements.slotB.classList.remove('hovering');    elements.slotC.classList.remove('hovering');    elements.slotD.classList.remove('hovering');        // ж·»еҠ ж–°зҡ„й«ҳдә®    if (isOverSlotA) {        elements.slotA.classList.add('highlight', 'hovering');    } else if (isOverSlotB) {        elements.slotB.classList.add('highlight', 'hovering');    } else if (isOverSlotC) {        elements.slotC.classList.add('highlight', 'hovering');    } else if (isOverSlotD) {        elements.slotD.classList.add('highlight', 'hovering');    } else if (isOverLogicEye) {        elements.logicEye.classList.add('highlight');    } else if (isOverEmpathyEye) {        elements.empathyEye.classList.add('highlight');    }        // иҝ”еӣһжҳҜеҗҰеңЁйҖүйЎ№дёҠж–№    return isOverSlotA || isOverSlotB || isOverSlotC || isOverSlotD;}// жЈҖжҹҘж”ҫзҪ®зӣ®ж ?function checkDropTarget(x, y) {    const slotA = elements.slotA.getBoundingClientRect();    const slotB = elements.slotB.getBoundingClientRect();    const slotC = elements.slotC.getBoundingClientRect();    const slotD = elements.slotD.getBoundingClientRect();    const logicEye = elements.logicEye.getBoundingClientRect();    const empathyEye = elements.empathyEye.getBoundingClientRect();    const restSlot = elements.restSlot ? elements.restSlot.getBoundingClientRect() : null;        // жү©еӨ§жҙһеҜҹд№Ӣзңјзҡ„жЈҖжөӢеҢәеҹ?    const expandedLogicEye = expandRect(logicEye, 40);    const expandedEmpathyEye = expandRect(empathyEye, 40);        if (isOverElement(x, y, slotA)) return { type: 'slot', slot: 'A' };    if (isOverElement(x, y, slotB)) return { type: 'slot', slot: 'B' };    if (isOverElement(x, y, slotC)) return { type: 'slot', slot: 'C' };    if (isOverElement(x, y, slotD)) return { type: 'slot', slot: 'D' };    if (isOverElement(x, y, expandedLogicEye)) return { type: 'insight', eye: 'logic' };    if (isOverElement(x, y, expandedEmpathyEye)) return { type: 'insight', eye: 'empathy' };    if (restSlot && isOverElement(x, y, restSlot)) return { type: 'rest' };        return null;}// жү©еӨ§зҹ©еҪўеҢәеҹҹfunction expandRect(rect, padding) {    return {        left: rect.left - padding,        right: rect.right + padding,        top: rect.top - padding,        bottom: rect.bottom + padding    };}// жЈҖжҹҘжҳҜеҗҰеңЁе…ғзҙ дёҠж–№function isOverElement(x, y, rect) {    return x >= rect.left && x <= rect.right && y >= rect.top && y <= rect.bottom;}// еӨ„зҗҶж”ҫзҪ®function handleDrop(result) {    const card = elements.card;    const dragData = gameState.dragData;        // и®Ўз®—жӢ–жӢҪйҖҹеәҰе’ҢзҠ№иұ«ж—¶й—?    const dragDuration = Date.now() - dragData.startTime;    const isQuickDrag = dragDuration < 500;    const isHesitant = checkHesitation(dragData.trail);        if (result.type === 'slot') {        // жЈҖжҹҘжҳҜеҗҰеҸҜд»Ҙз«ӢеҚіиЎҢеҠ?        if (!gameState.hasInsight && gameState.resources.energy <= 0) {            showRestPopup();            card.style.transform = '';            card.classList.remove('dragging');            return;        }                // еӨ„зҗҶйҖүжӢ©        processChoice(result.slot, isQuickDrag, isHesitant);            } else if (result.type === 'insight') {        // жЈҖжҹҘиө„жә?        const resourceType = result.eye === 'logic' ? 'logic' : 'empathy';        if (gameState.resources[resourceType] < 1) {            card.style.transform = '';            card.classList.remove('dragging');            return;        }                // жү§иЎҢжҙһеҜҹ        performInsight(result.eye);    } else if (result.type === 'rest') {        performRest();    }        // йҮҚзҪ®еҚЎзүҢдҪҚзҪ®    setTimeout(() => {        card.style.transform = '';        card.classList.remove('dragging');    }, 100);}// жЈҖжҹҘзҠ№иұ?function checkHesitation(trail) {    if (trail.length < 10) return false;        // з®ҖеҚ•зҡ„зҠ№иұ«жЈҖжөӢпјҡжЈҖжҹҘиҪЁиҝ№ж–№еҗ‘еҸҳеҢ?    let directionChanges = 0;    for (let i = 2; i < trail.length; i++) {        const dx1 = trail[i - 1].x - trail[i - 2].x;        const dx2 = trail[i].x - trail[i - 1].x;        if (dx1 * dx2 < 0) directionChanges++;    }        return directionChanges > 3;}// еӨ„зҗҶйҖүжӢ©function processChoice(slot, isQuickDrag, isHesitant) {    // жё…йҷӨеҖ’и®Ўж—¶е®ҡж—¶еҷЁпјҢйҒҝе…Қз”ЁжҲ·йҖүжӢ©еҗҺеҖ’и®Ўж—¶з»§з»ӯеҜјиҮҙйҮҚеӨҚйҖүжӢ©    if (gameState.countdownInterval) {        clearInterval(gameState.countdownInterval);        gameState.countdownInterval = null;        elements.countdownContainer.classList.add('hidden');        gameState.isTimePressure = false;    }        const currentCard = gameState.cards[gameState.currentCardIndex];    let type;        // ж №жҚ®йҖүжӢ©зҡ„ж§ҪдҪҚзЎ®е®ҡзұ»еһ?    if (slot === 'A') type = currentCard.aType;    else if (slot === 'B') type = currentCard.bType;    else if (slot === 'C') type = currentCard.cType;    else if (slot === 'D') type = currentCard.dType;        // ж¶ҲиҖ—иө„жә?    if (!gameState.hasInsight) {        gameState.resources.energy = Math.max(0, gameState.resources.energy - 1);        gameState.totalUsed.energy += 1;    }        // ж №жҚ®йҖүжӢ©зҡ„зұ»еһӢи°ғж•ҙMBTIз»ҙеәҰеҲҶж•°    // E/Iз»ҙеәҰ    if (type === 'E') {        gameState.qxrgScores.E += 1;    } else if (type === 'I') {        gameState.qxrgScores.I += 1;    }    // S/Nз»ҙеәҰ    else if (type === 'S') {        gameState.qxrgScores.S += 1;    } else if (type === 'N') {        gameState.qxrgScores.N += 1;    }    // T/Fз»ҙеәҰ    else if (type === 'T') {        gameState.qxrgScores.T += 1;    } else if (type === 'F') {        gameState.qxrgScores.F += 1;    }    // J/Pз»ҙеәҰ    else if (type === 'J') {        gameState.qxrgScores.J += 1;    } else if (type === 'P') {        gameState.qxrgScores.P += 1;    }        // иө„жәҗи°ғж•ҙ - жүҖжңүйҖүжӢ©йғҪеўһеҠ зІҫеҠ?    gameState.resources.energy = Math.min(gameState.resources.maxEnergy, gameState.resources.energy + 1);        // и®Ўз®—еҲҶж•°пјҲеҹәзЎҖеҲҶж•°пј?    let score = gameState.hasInsight ? 2 : 1;        // еҝ«йҖҹеҶізӯ–еҠ еҲ?    if (isQuickDrag) score += 0.5;        // зҠ№иұ«еҮҸеҲҶ    if (isHesitant) score -= 0.3;        // зҙҜеҠ жҖ»еҲҶ    gameState.totalScore += score;        // qxrgеҲҶж•°е·ІеңЁдёҠйқўж №жҚ®typeзҙҜеҠ пјҢиҝҷйҮҢеҸӘзҙҜеҠ йўқеӨ–еҲҶж•°    // еҲҶж•°з”ЁдәҺжңҖз»ҲиҜ„жҳҹпјҢдёҚеҪұе“Қдәәж јзұ»еһ?        // жӣҙж–°Combo    updateCombo(type);        // жЈҖжҹҘжҳҜеҗҰеҗ¬д»Һе»әи®?    if (gameState.recommendedSlot === slot) {        gameState.trust = Math.min(gameState.maxTrust, gameState.trust + 1);    } else if (gameState.recommendedSlot !== null) {        gameState.trust = Math.max(0, gameState.trust - 1);    }        // еҲӣе»әжҲҗеҠҹзү№ж•Ҳ    createSuccessParticles();        // жҳҫзӨәж§ҪдҪҚеҠЁз”»    let slotElement;    if (slot === 'A') slotElement = elements.slotA;    else if (slot === 'B') slotElement = elements.slotB;    else if (slot === 'C') slotElement = elements.slotC;    else if (slot === 'D') slotElement = elements.slotD;    slotElement.classList.add('slot-success');    setTimeout(() => slotElement.classList.remove('slot-success'), 400);        // жӣҙж–°иө„жәҗжҳҫзӨә    updateResourceDisplay();        // дёӢдёҖеј еҚЎзү?    nextCard();}// жӣҙж–°Combofunction updateCombo(type) {    const dimensionTypes = {        'E': 'EI', 'I': 'EI',        'S': 'SN', 'N': 'SN',        'T': 'TF', 'F': 'TF',        'J': 'JP', 'P': 'JP'    };        const currentDimension = dimensionTypes[type];    const lastDimension = gameState.combo.lastType ? dimensionTypes[gameState.combo.lastType] : null;        if (currentDimension === lastDimension) {        gameState.combo[type]++;                if (gameState.combo[type] >= 3) {            // и§ҰеҸ‘Comboзү№ж•Ҳ            showComboEffect(type);            // йўқеӨ–еҠ еҲҶ            gameState.qxrgScores[type] += 1;        }    } else {        // йҮҚзҪ®Combo        Object.keys(gameState.combo).forEach(key => {            if (key !== 'lastType') gameState.combo[key] = 0;        });    }        gameState.combo.lastType = type;}// жҳҫзӨәComboзү№ж•Ҳfunction showComboEffect(type) {    const effect = document.createElement('div');    effect.className = 'combo-effect';    effect.textContent = `${type} COMBO!`;    document.body.appendChild(effect);        // зҒ«з„°зү№ж•Ҳ    const fireEffect = document.createElement('div');    fireEffect.className = 'fire-effect';    document.body.appendChild(fireEffect);        setTimeout(() => {        effect.remove();        fireEffect.remove();    }, 1000);}// жү§иЎҢжҙһеҜҹfunction performInsight(eyeType) {    const currentCard = gameState.cards[gameState.currentCardIndex];        // жЈҖжҹҘжҳҜеҗҰе·Із»ҸиҝӣиЎҢиҝҮд»»дҪ•жҙһеҜҹпјҲжҜҸдёӘеҚЎзүҢеҸӘиғҪдҪҝз”ЁдёҖж¬ЎжҙһеҜҹпјү    if (currentCard.hasLogicInsight || currentCard.hasEmpathyInsight) {        // е·Із»ҸжҙһеҜҹиҝҮпјҢдёҚжү§иЎ?        elements.card.style.transform = '';        elements.card.classList.remove('dragging');        return;    }        // жЈҖжҹҘиө„жәҗжҳҜеҗҰи¶іеӨ?    if (eyeType === 'logic' && gameState.resources.logic < 1) {        elements.card.style.transform = '';        elements.card.classList.remove('dragging');        return;    }    if (eyeType === 'empathy' && gameState.resources.empathy < 1) {        elements.card.style.transform = '';        elements.card.classList.remove('dragging');        return;    }        // ж¶ҲиҖ—еҜ№еә”иө„жә?    if (eyeType === 'logic') {        gameState.resources.logic--;        gameState.totalUsed.logic++;        currentCard.hasLogicInsight = true;        // зҰҒз”Ёе…ұжғ…жҙһеҜҹпјҲж•ҙдёӘе®№еҷЁеҸҳзҒ°пјү        elements.empathyEyeContainer.classList.add('disabled');    } else {        gameState.resources.empathy--;        gameState.totalUsed.empathy++;        currentCard.hasEmpathyInsight = true;        // зҰҒз”ЁйҖ»иҫ‘жҙһеҜҹпјҲж•ҙдёӘе®№еҷЁеҸҳзҒ°пјү        elements.logicEyeContainer.classList.add('disabled');    }        // ж Үи®°е·Із»ҸиҝӣиЎҢиҝҮжҙһеҜҹпјҲдёӨз§ҚжҙһеҜҹйғҪдёҚиғҪеҶҚз”Ёпјү    gameState.hasInsight = true;    gameState.insightType = eyeType;        // ж·Ўе…Ҙж·ЎеҮәж•Ҳжһңжӣҙж–°ж–Үеӯ—еҶ…е®№    const card = elements.card;    elements.cardDesc.style.opacity = '0';        setTimeout(() => {        // ж №жҚ®жҙһеҜҹзұ»еһӢжҳҫзӨәдёҚеҗҢеҶ…е®№        elements.cardDesc.textContent = eyeType === 'logic' ? currentCard.logicDesc : currentCard.empathyDesc;        elements.cardStatus.textContent = eyeType === 'logic' ? "е·ІйҖ»иҫ‘жҙһеҜҹ" : "е·Іе…ұжғ…жҙһеҜ?;        elements.cardDesc.style.opacity = '1';    }, 200);        updateResourceDisplay();}// жү§иЎҢдј‘жҒҜfunction performRest() {    // жҒўеӨҚиө„жәҗ    gameState.resources.energy = Math.min(gameState.resources.maxEnergy, gameState.resources.energy + 3);    gameState.resources.logic = Math.min(gameState.resources.maxLogic, gameState.resources.logic + 2);    gameState.resources.empathy = Math.min(gameState.resources.maxEmpathy, gameState.resources.empathy + 2);        // еўһеҠ з„Ұиҷ‘еҖ?    gameState.mood.anxiety = Math.min(10, gameState.mood.anxiety + 1);    gameState.mood.calm = 10 - gameState.mood.anxiety;        // йҡҗи—Ҹдј‘жҒҜеј№зӘ—    elements.restPopup.classList.add('hidden');        updateResourceDisplay();    updateMoodDisplay();}// жҳҫзӨәдј‘жҒҜеј№зӘ—function showRestPopup() {    elements.restPopup.classList.remove('hidden');        // еҗҜз”Ёдј‘жҒҜж§Ҫзҡ„жӢ–жӢҪжЈҖжөӢпјҲз®ҖеҢ–еӨ„зҗҶпјү    elements.restSlot.addEventListener('click', () => {        performRest();    }, { once: true });}// дёӢдёҖеј еҚЎзү?function nextCard() {    elements.card.classList.add('card-exit');        setTimeout(() => {        gameState.currentCardIndex++;        gameState.hasInsight = false;        gameState.insightType = null;        gameState.recommendedSlot = null;                if (gameState.currentCardIndex >= gameState.cards.length) {            showResult();        } else {            loadCard();        }    }, 300);}// еҠ иҪҪеҚЎзүҢfunction loadCard() {    const card = gameState.cards[gameState.currentCardIndex];        // жҒўеӨҚжҙһеҜҹд№ӢзңјзҠ¶жҖ?    elements.logicEyeContainer.classList.remove('disabled');    elements.empathyEyeContainer.classList.remove('disabled');        elements.cardTitle.textContent = card.title;    elements.cardDesc.textContent = card.partialDesc;    elements.cardStatus.textContent = "з«ӢеҚіиЎҢеҠЁ - ж¶ҲиҖ?зІҫеҠӣ";    elements.slotAText.textContent = card.optionA;    elements.slotBText.textContent = card.optionB;    elements.slotCText.textContent = card.optionC;    elements.slotDText.textContent = card.optionD;        // йҮҚзҪ®еҚЎзүҢж ·ејҸ    elements.card.classList.remove('card-exit');    elements.card.classList.add('card-enter');    setTimeout(() => elements.card.classList.remove('card-enter'), 500);        // жӣҙж–°иҝӣеәҰ    elements.cardIndex.textContent = gameState.currentCardIndex + 1;    elements.gameProgressBar.style.width = `${((gameState.currentCardIndex + 1) / gameState.cards.length) * 100}%`;        // жЈҖжҹҘзү№ж®ҠдәӢд»?- ж №жҚ®жёёжҲҸиҝӣеәҰи°ғж•ҙеҖ’и®Ўж—¶еҚЎзүҢеҮәзҺ°йў‘зҺ?    if (card.isTimePressure) {        // еҗҺжңҹпјҲз¬¬20еј д№ӢеҗҺпјүйҷҚдҪҺеҖ’и®Ўж—¶еҚЎзүҢеҮәзҺ°йў‘зҺ?        const cardIndex = gameState.currentCardIndex;        const totalCards = gameState.cards.length;        let shouldTrigger = true;                // з¬?0еј д№ӢеҗҺпјҢеҖ’и®Ўж—¶еҚЎзүҢеҮәзҺ°жҰӮзҺҮйҖҗжёҗйҷҚдҪҺ        if (cardIndex >= 19) { // з¬?0еј еҚЎзүҢејҖе§ӢпјҲзҙўеј•19пј?            const progress = (cardIndex - 19) / (totalCards - 19);            // жҰӮзҺҮд»?00%йҖҗжёҗйҷҚдҪҺеҲ?0%            const probability = 1 - progress * 0.6;            shouldTrigger = Math.random() < probability;        }                if (shouldTrigger) {            startCountdown();        }    }        if (card.hasNotification) {        setTimeout(() => showNotification(), 1000);    }        // жӣҙж–°иө„жәҗйҷҗеҲ¶жҳҫзӨә    updateSlotAvailability();}// ејҖе§ӢеҖ’и®Ўж—?function startCountdown() {    // е…Ҳжё…йҷӨе·Іжңүзҡ„еҖ’и®Ўж—?    if (gameState.countdownInterval) {        clearInterval(gameState.countdownInterval);        gameState.countdownInterval = null;    }        gameState.isTimePressure = true;    gameState.timeRemaining = 15; // ж”№дёә15з§?    gameState.countdownSpeed = 1;        elements.countdownContainer.classList.remove('hidden');    elements.countdownTimer.textContent = gameState.timeRemaining;    elements.countdownReason.classList.remove('hidden');    elements.shakeReason.classList.add('hidden');    elements.timePressureIndicator.classList.remove('hidden');        gameState.countdownInterval = setInterval(() => {        gameState.timeRemaining--;        elements.countdownTimer.textContent = gameState.timeRemaining;                if (gameState.timeRemaining <= 0) {            clearInterval(gameState.countdownInterval);            gameState.countdownInterval = null;            elements.countdownContainer.classList.add('hidden');            elements.timePressureIndicator.classList.add('hidden');                        // ж—¶й—ҙеҲ°пјҢиҮӘеҠЁйҖүжӢ©пјҲеўһеҠ з„Ұиҷ‘пјү            gameState.mood.anxiety = Math.min(10, gameState.mood.anxiety + 2);            gameState.mood.calm = 10 - gameState.mood.anxiety;            const randomSlot = ['A', 'B', 'C', 'D'][Math.floor(Math.random() * 4)];            processChoice(randomSlot, false, true);            updateMoodDisplay();        }    }, 1000);}// йҖҡзҹҘеҶ…е®№еҲ—иЎЁпјҲеёҰйҖүйЎ№пј?const notificationContents = [    {         title: "е·ҘдҪңж¶ҲжҒҜ",         content: "йЎ№зӣ®иҝӣеәҰжӣҙж–°пјҡжң¬е‘Ёд»»еҠЎе·Іе®ҢжҲҗ80%",        options: ["дёәеӣўйҳҹжҲҗе°ұж„ҹеҲ°жҝҖе